export function getNumberContent(number: number): number {
  if (number === 11 || number === 22 || number === 33) {
    return number;
  }
  if (number > 9) {
    return getNumberContent(number.toString().split('').reduce((a, b) => a + parseInt(b), 0));
  }
  return number;
}
